INSERT INTO public.questions (id, exam_id, paper_id, subject_id, chapter_id, question_type, question_text, options, correct_answer, correct_answer_json, auto_gradable, source, is_active, version, source_meta, explanation)
VALUES
  ('disabled-57f41407-moex-00316', 'disabled-57f41407', 'disabled-57f41407-moex-112-34c7f7f6', 'sub-disabled-57f41407-01', NULL, 'single_choice', '「上善的人像水一樣：水能滋養萬物，不和萬物相爭，蓄居在大家不喜歡 的卑下之處，有這些特性，所以水是很接近『道』了。上善的人處身退讓 安靜，這像水的『處眾人之所惡』；博施而不望報，說話真誠不妄，為政 能獲得好成績，這像水的『利萬物』；行動則能掌握時機，這像水的『不 爭』；因為不和人相爭，所以沒有怨尤。」 根據上文，下列選項不符合上善之人的特性是︰', '["感恩戴德", "處身謙遜", "推誠布信", "經綸濟世"]'::jsonb, 0, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:38:36+00:00", "source_pdf_sha1": "5c2eaeb81861", "answer_pdf_sha1": "ad67f96c0b18", "source_family": "moex-gov-tw", "moex": {"exam_code": "112050", "c": "506", "s": "0105", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "國文", "year": "112", "exam_name": "112年公務人員特種考試關務人員考試、身心障礙人員考試、國軍上校以上軍官轉任公務人員考試", "original_question_number": 16, "answer_corrected": false, "flags": [], "civil_slug": "disabled", "civil_category": "錄事"}'::jsonb, NULL),
  ('disabled-57f41407-moex-00317', 'disabled-57f41407', 'disabled-57f41407-moex-112-34c7f7f6', 'sub-disabled-57f41407-01', NULL, 'single_choice', '「第二次世界大戰結束的同時，日人擔心神社被國民政府破壞，自行燒毀 部分神社。根據地方上耆老的說法，大湳祠（新竹州八卦山社）和知本祠 （臺東廳臺東郡）都燒毀了，而開山神社雖於新社殿執行『昇神』之儀， 但舊社殿（原開山王廟）因安置鄭成功塑像，因而例外，自大陸進駐的文 武官會來此列隊，以臺灣式祭儀舉行祭典。」 根據上文，對於二戰後臺灣「日本神社」的敘述，何者正確？', '["國民政府來臺後，下令日本人自行燒毀神社", "部分神社如大湳祠、知本祠，是被地方耆老燒毀的", "開山神社舊社殿供奉鄭成功像，日本人選擇保存下來", "來自大陸的文武官員，拒絕為鄭成功舉辦臺灣式祭典"]'::jsonb, 2, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:38:36+00:00", "source_pdf_sha1": "5c2eaeb81861", "answer_pdf_sha1": "ad67f96c0b18", "source_family": "moex-gov-tw", "moex": {"exam_code": "112050", "c": "506", "s": "0105", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "國文", "year": "112", "exam_name": "112年公務人員特種考試關務人員考試、身心障礙人員考試、國軍上校以上軍官轉任公務人員考試", "original_question_number": 17, "answer_corrected": false, "flags": [], "civil_slug": "disabled", "civil_category": "錄事"}'::jsonb, NULL),
  ('disabled-57f41407-moex-00318', 'disabled-57f41407', 'disabled-57f41407-moex-112-34c7f7f6', 'sub-disabled-57f41407-01', NULL, 'single_choice', '「『蓮花出淤泥而不染，濯清漣而不妖』述說著蓮花的聖潔，如果我們在 顯微鏡下看蓮葉，表面有許多微米級的凸起和蠟質的外皮組織；再放大倍 率看下去，則有更多的奈米級微細結構出現在微米級凸起上。這種多層次 結構及蠟質結晶組成的疏水特性，讓任何東西都不易沾黏，連水珠也是圓 滾滾的『站』在上面；而表面上的疏水特性更有助於髒東西被雨水沖走， 細菌不易孳生。」 根據上文，下列選項何者最符合文意？', '["蓮葉的聖潔感來自於微米級的細微結晶", "蓮葉奈米級的鮮嫩色澤不容易孳生細菌", "微米級凸起上的奈米級結構形成了蓮葉的疏水特性", "蠟質外皮組織有助於蓮葉外觀常保潔淨和水分潤澤"]'::jsonb, 2, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:38:36+00:00", "source_pdf_sha1": "5c2eaeb81861", "answer_pdf_sha1": "ad67f96c0b18", "source_family": "moex-gov-tw", "moex": {"exam_code": "112050", "c": "506", "s": "0105", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "國文", "year": "112", "exam_name": "112年公務人員特種考試關務人員考試、身心障礙人員考試、國軍上校以上軍官轉任公務人員考試", "original_question_number": 18, "answer_corrected": false, "flags": [], "civil_slug": "disabled", "civil_category": "錄事"}'::jsonb, NULL),
  ('disabled-57f41407-moex-00319', 'disabled-57f41407', 'disabled-57f41407-moex-112-34c7f7f6', 'sub-disabled-57f41407-01', NULL, 'single_choice', '「詩的本質，存於個人而不在於物。就有眼光的人看來，宇宙間一切事物 或現象，都會覺得完全具有詩性。確實，詩人能從一切無趣味、煞風景、 俗惡的東西中挖掘詩的美感、豐富詩的世界。所以關鍵不是問什麼是詩， 而是問詩人感物的態度是什麼？」 根據上文，下列選項何者最接近文意？', '["美是詩的象徵，詩也是美的本質", "世間從不缺少美，而是缺少發現", "詩有快樂美善的特質，所以感人", "美好的靈魂，也具備美麗的外表"]'::jsonb, 1, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:38:36+00:00", "source_pdf_sha1": "5c2eaeb81861", "answer_pdf_sha1": "ad67f96c0b18", "source_family": "moex-gov-tw", "moex": {"exam_code": "112050", "c": "506", "s": "0105", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "國文", "year": "112", "exam_name": "112年公務人員特種考試關務人員考試、身心障礙人員考試、國軍上校以上軍官轉任公務人員考試", "original_question_number": 19, "answer_corrected": false, "flags": [], "civil_slug": "disabled", "civil_category": "錄事"}'::jsonb, NULL),
  ('disabled-57f41407-moex-00320', 'disabled-57f41407', 'disabled-57f41407-moex-112-34c7f7f6', 'sub-disabled-57f41407-01', NULL, 'single_choice', '「人一出生，其實就跟這個世界、跟他人之間有種『感通』的能量。如閱 讀文學時的感動，從《詩經》、《楚辭》到陶淵明、杜甫，能把別人的苦 痛變成自己生命的一部分。或是儒家思想所講的『惻隱』、『不忍』之心， 都是感通，這背後預設自我分享了別人的命運，他人就在個體的自我裡。 我們所要做的是讓這種能量變強，讓自己更能理解別人在想什麼。」 根據上文，下列選項何者正確？', '["感通力量人人皆備，只是文學家表達更為精準", "抒發情感貴在樸實真誠，才能更深入打動人心", "感通是自我能同理他人，將他人納入己身生命", "個體與群體之關係，可在傳統中找到所有答案"]'::jsonb, 2, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:38:36+00:00", "source_pdf_sha1": "5c2eaeb81861", "answer_pdf_sha1": "ad67f96c0b18", "source_family": "moex-gov-tw", "moex": {"exam_code": "112050", "c": "506", "s": "0105", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "國文", "year": "112", "exam_name": "112年公務人員特種考試關務人員考試、身心障礙人員考試、國軍上校以上軍官轉任公務人員考試", "original_question_number": 20, "answer_corrected": false, "flags": [], "civil_slug": "disabled", "civil_category": "錄事"}'::jsonb, NULL),
  ('disabled-57f41407-moex-00321', 'disabled-57f41407', 'disabled-57f41407-moex-112-34c7f7f6', 'sub-disabled-57f41407-01', NULL, 'single_choice', '「可以鳳求凰或凰求鳯，可以叫賣價格低廉而美輪美奐的瓊樓玉宇，可以 報失，可以道歉，可以鳴謝救火，可以感謝良醫，可以宣揚仙丹，可以賀 人結婚，可以賀人家的兒子得博士學位，可以一大排一大排訃告同一某某 董事長的死訊，可以公開訴願喊冤，可以公開歌功頌德，可以宣告為某某 舉辦冥壽，可以公告拒絕往來戶，可以揭露各種考試的金榜，可以……不 勝枚舉。」 根據上文，可以有如此多功用的是指：', '["證書", "廣告", "新聞", "招牌"]'::jsonb, 1, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:38:36+00:00", "source_pdf_sha1": "5c2eaeb81861", "answer_pdf_sha1": "ad67f96c0b18", "source_family": "moex-gov-tw", "moex": {"exam_code": "112050", "c": "506", "s": "0105", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "國文", "year": "112", "exam_name": "112年公務人員特種考試關務人員考試、身心障礙人員考試、國軍上校以上軍官轉任公務人員考試", "original_question_number": 21, "answer_corrected": false, "flags": [], "civil_slug": "disabled", "civil_category": "錄事"}'::jsonb, NULL),
  ('disabled-57f41407-moex-00322', 'disabled-57f41407', 'disabled-57f41407-moex-112-34c7f7f6', 'sub-disabled-57f41407-01', NULL, 'single_choice', '「提出好問題對每個人來說都很重要。真正的好朋友會拿好問題來問你， 就像好父母一樣。從他們提出的問題，就可以知道他們對你的了解，還有 多麼關心你。他們提出的問題，會讓你停下來，好好思考，要你誠懇面對 自己，至於你是否真的能夠找到答案，倒不是那麼重要。提出讓人不禁思 考的好問題是一門藝術，我相信，也是一種值得好好培養的能力。」 根據上文，下列選項何者最符合文意？', '["好父母會像好朋友提出一樣的關鍵問題", "好的問題如同交友一樣，也是一門藝術", "從問題可了解提問者對我們的關注程度", "能夠誠懇地面對好問題，就能找到答案"]'::jsonb, 2, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:38:36+00:00", "source_pdf_sha1": "5c2eaeb81861", "answer_pdf_sha1": "ad67f96c0b18", "source_family": "moex-gov-tw", "moex": {"exam_code": "112050", "c": "506", "s": "0105", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "國文", "year": "112", "exam_name": "112年公務人員特種考試關務人員考試、身心障礙人員考試、國軍上校以上軍官轉任公務人員考試", "original_question_number": 22, "answer_corrected": false, "flags": [], "civil_slug": "disabled", "civil_category": "錄事"}'::jsonb, NULL),
  ('disabled-57f41407-moex-00323', 'disabled-57f41407', 'disabled-57f41407-moex-112-34c7f7f6', 'sub-disabled-57f41407-01', NULL, 'single_choice', '「我們常覺得是自己在做決定，但事實上在缺乏資訊時，會藉由觀察別人， 盡量蒐集片段的資料，然後加以模仿。模仿可以是個正當的策略，是一種 『社會學習』，透過和其他人的互動來學習，比自己獨力應付狀況時更聰 明些。不過模仿卻也經常把大家帶離正軌，因為模仿並不會產生任何新資 訊，只是擴大一些舊資訊可以帶來的效果，並且不管資訊是真是假。」 根據上文，下列選項最符合文意的是：', '["人們在絕大多數時間所下的決定，其實都並非出自自我判斷", "模仿其實也是不錯的學習方式，只要能在正當運用的範圍內", "社會學習意指由社會群體來做決定，以避免專斷獨裁的危險", "資訊充沛的時代，蒐集資料、觀察別人，是正確的學習策略"]'::jsonb, 1, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:38:36+00:00", "source_pdf_sha1": "5c2eaeb81861", "answer_pdf_sha1": "ad67f96c0b18", "source_family": "moex-gov-tw", "moex": {"exam_code": "112050", "c": "506", "s": "0105", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "國文", "year": "112", "exam_name": "112年公務人員特種考試關務人員考試、身心障礙人員考試、國軍上校以上軍官轉任公務人員考試", "original_question_number": 23, "answer_corrected": false, "flags": [], "civil_slug": "disabled", "civil_category": "錄事"}'::jsonb, NULL),
  ('disabled-57f41407-moex-00324', 'disabled-57f41407', 'disabled-57f41407-moex-112-34c7f7f6', 'sub-disabled-57f41407-01', NULL, 'single_choice', '「前不久，我返家，彷彿已經老去卻又元氣十足的奶奶，親暱地坐在我身 邊問我人生前途的種種課題，那些我答不出來也無意抵達的目標、方向、 可能。對話像飄搖的小舟行駛在晴日之海，懶洋洋。」 根據上文，下列選項最接近祖母和作者對話狀態的是：', '["作者有一搭沒一搭地被動回應祖母", "作者積極回應祖母，兩人聊得愉快", "祖母明知故問，作者只能羞愧沉默", "兩人互相試探，宛如小型的攻防戰"]'::jsonb, 0, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:38:36+00:00", "source_pdf_sha1": "5c2eaeb81861", "answer_pdf_sha1": "ad67f96c0b18", "source_family": "moex-gov-tw", "moex": {"exam_code": "112050", "c": "506", "s": "0105", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "國文", "year": "112", "exam_name": "112年公務人員特種考試關務人員考試、身心障礙人員考試、國軍上校以上軍官轉任公務人員考試", "original_question_number": 24, "answer_corrected": false, "flags": [], "civil_slug": "disabled", "civil_category": "錄事"}'::jsonb, NULL),
  ('disabled-57f41407-moex-00325', 'disabled-57f41407', 'disabled-57f41407-moex-112-34c7f7f6', 'sub-disabled-57f41407-01', NULL, 'single_choice', '常言道：「這世界最可敬的事，就是比你聰明的人，卻比你還更加認真， 積極求上。」下列選項，最接近文意的是：', '["學如逆水行舟，不進則退", "一分天才，九十九分努力", "坐等機會，終將一事無成", "學海無涯，惟勤勞能補拙"]'::jsonb, 1, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:38:36+00:00", "source_pdf_sha1": "5c2eaeb81861", "answer_pdf_sha1": "ad67f96c0b18", "source_family": "moex-gov-tw", "moex": {"exam_code": "112050", "c": "506", "s": "0105", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "國文", "year": "112", "exam_name": "112年公務人員特種考試關務人員考試、身心障礙人員考試、國軍上校以上軍官轉任公務人員考試", "original_question_number": 25, "answer_corrected": false, "flags": [], "civil_slug": "disabled", "civil_category": "錄事"}'::jsonb, NULL)
